SELECT COUNT(1)
FROM conversation
WHERE user_id = #{userId}

SELECT COUNT(1) FROM conversation c
AND c.user_id = #{userId}
AND ( c.title LIKE CONCAT('%', #{keyword}, '%') OR c.last_message LIKE CONCAT('%', #{keyword}, '%') OR CAST(c.id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') )

SELECT c.id, c.user_id AS userId, COALESCE(NULLIF(TRIM(u.name), ''), u.username, CAST(u.id AS CHAR)) AS userDisplayName, c.character_id AS characterId, a.name AS characterName, c.title, c.last_message AS lastMessage, c.last_msg_at AS lastMsgAt, c.create_time AS createTime, c.update_time AS updateTime FROM conversation c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN ai_character a ON c.character_id = a.id
AND c.user_id = #{userId}
AND ( c.title LIKE CONCAT('%', #{keyword}, '%') OR c.last_message LIKE CONCAT('%', #{keyword}, '%') OR CAST(c.id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY COALESCE(c.last_msg_at, c.update_time) DESC LIMIT #{size} OFFSET #{offset}
